 * Zero external dependencies. Works in all modern browsers.
 *
 * Features: sorting, filtering, pagination, column toggling,
 * copy-to-clipboard, CSV download, search highlighting, sticky header.
 */
(function () {
  "use strict";

  var DEBOUNCE_MS = 200;
  var COPIED_MS = 2000;
